Code.Terraform:
```hcl
# WAF Classic Global ルールに少なくとも 1 つの条件があることを確認してください
resource "aws_waf_rule" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_metric_name>"

  # 重要: ルールが空にならないように、少なくとも1つの述語（条件）を追加してください
  predicate {
    data_id = "<example_resource_id>"  # 既存のIPSet ID
    negated = false
    type    = "IPMatch"
  }
}
```
